export const destacadasDe = (slug: string): OfertaDestacada[] =>
  OFERTAS_DESTACADAS.filter((o) => o.pais === slug);

// Slug y URL de la página de detalle de cada empresa (para SEO: una página por empresa).
export const slugEmpresa = (o: OfertaDestacada): string =>
  `${o.empresa}-${o.titulo}`
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 70);

export const detalleUrl = (o: OfertaDestacada): string =>
  `/empleos/${o.pais}/${slugEmpresa(o)}`;

// Logo real de la empresa (vía servicio de Google) a partir del dominio de su web.
// Se omite en portales de empleo externos (ATS) donde el dominio no es el de la marca.
const ATS_HOSTS = ['avature.net', 'myworkdayjobs.com', 'oraclecloud.com', 'icims.com', 'smartrecruiters.com', 'taleo.net', 'workday.com'];
export const logoUrl = (o: OfertaDestacada): string | null => {
  try {
    const h = new URL(o.url).hostname.replace(/^www\./, '');
    if (ATS_HOSTS.some((a) => h === a || h.endsWith('.' + a))) return null;
    return `https://www.google.com/s2/favicons?sz=128&domain=${h}`;
  } catch {
    return null;
  }
};
